DROP TRIGGER IF EXISTS tbiu_sc_atm_lon_detail ON sc_atm_lon_detail CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_lon_detail() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_atm_lon_detail
    where (loan_contract_no = NEW.loan_contract_no);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;

  if coalesce(NEW.ref_sys_lon::text, '') = '' or NEW.ref_sys_lon = 0 then
    if NEW.item_type in ('AT','RA') then
      select max(seq_no) into STRICT NEW.ref_sys_lon
      from sc_lon_m_loan_card_detail
      where (loan_contract_no = NEW.loan_contract_no);
      NEW.ref_sys_lon := coalesce(NEW.ref_sys_lon,0);
    else
      NEW.ref_sys_lon := 0;
    end if;
  end if;

  if coalesce(NEW.prin_amount::text, '') = '' then NEW.prin_amount :=0;end if;
  if coalesce(NEW.fee_amount::text, '') = '' then NEW.fee_amount :=0;end if;
  if coalesce(NEW.loan_balance::text, '') = '' then NEW.loan_balance :=0;end if;
  if coalesce(NEW.approve_amount::text, '') = '' then NEW.approve_amount :=0;end if;

  if coalesce(OLD.LOAN_CONTRACT_NO::text, '') = '' and (NEW.LOAN_CONTRACT_NO IS NOT NULL AND NEW.LOAN_CONTRACT_NO::text <> '') then
    if pka.auto_entry then 
      NEW.entry_id := current_setting('app.login_id', true);
      NEW.entry_date := statement_timestamp();
      NEW.entry_br := current_setting('app.login_br', true);
      NEW.entry_pc := pka_com_login.login_pc;
    end if;
  end if;


RETURN NEW;
end
$BODY$
